mapper.select:
SELECT * FROM dungeon_spawn_slot
WHERE dungeon_id = #{dungeonId}
  AND spawn_type = #{spawnType}
  AND engaged_character_id IS NULL
  AND respawn_at <= #{now}

mapper.update:
UPDATE dungeon_spawn_slot
SET engaged_character_id = #{characterId}
WHERE id = #{id}
  AND engaged_character_id IS NULL
  AND respawn_at <= #{now}

UPDATE dungeon_spawn_slot
SET engaged_character_id = NULL
WHERE id = #{id}
  AND engaged_character_id = #{characterId}

UPDATE dungeon_spawn_slot
SET engaged_character_id = NULL,
    respawn_at = #{respawnAt}
WHERE id = #{id}
  AND engaged_character_id = #{characterId}
